//! Adobe-Korea1 CID-to-Unicode mapping table.
//!
//! Generated from adobe-type-tools/cmap-resources Adobe-Korea1-2/cid2code.txt
//! UniKS-UCS2 column (first mapping per CID).

/// Look up a CID in the Adobe-Korea1 table and return the Unicode character.
pub fn lookup_korea1(cid: u16) -> Option<char> {
    ADOBE_KOREA1_CID_TO_UNICODE
        .binary_search_by_key(&cid, |&(c, _)| c)
        .ok()
        .and_then(|idx| char::from_u32(ADOBE_KOREA1_CID_TO_UNICODE[idx].1 as u32))
}

